// 1. Sadə readonly properties
interface User {
  readonly id: string;
  name: string;
}
const user: User = { id: "U001", name: "Murad" };
console.log(user); // Çıxış: { id: "U001", name: "Murad" }
user.name = "Alice"; // OK
// user.id = "U002"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 2. Readonly ilə siniflər
interface Vehicle {
  readonly brand: string;
  model?: string;
  getInfo(): string;
}
class Car implements Vehicle {
  readonly brand: string;
  model?: string;
  constructor(brand: string, model?: string) {
    this.brand = brand;
    this.model = model;
  }
  getInfo(): string {
    return this.model ? `${this.brand} ${this.model}` : this.brand;
  }
}
const car = new Car("Toyota", "Camry");
console.log(car.getInfo()); // Çıxış: Toyota Camry
// car.brand = "Honda"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 3. Readonly və optional xüsusiyyətlər
interface Product {
  readonly id: string;
  name: string;
  price?: number;
}
const product: Product = { id: "P001", name: "Laptop" };
console.log(product); // Çıxış: { id: "P001", name: "Laptop" }
product.name = "Mouse"; // OK
// product.id = "P002"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 4. Miras alma ilə readonly
interface Person {
  readonly id: string;
  name: string;
}
interface Employee extends Person {
  readonly role: string;
}
const employee: Employee = { id: "E001", name: "Alice", role: "Developer" };
console.log(employee); // Çıxış: { id: "E001", name: "Alice", role: "Developer" }
// employee.id = "E002"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz
// employee.role = "Manager"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 5. Readonly<T> utility tipi
interface Book {
  title: string;
  pages: number;
}
type ReadonlyBook = Readonly<Book>;
const book: ReadonlyBook = { title: "TypeScript Guide", pages: 200 };
console.log(book); // Çıxış: { title: "TypeScript Guide", pages: 200 }
// book.title = "New Book"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 6. Union tipləri ilə readonly
interface Book {
  type: "book";
  readonly title: string;
  pages?: number;
}
interface Movie {
  type: "movie";
  readonly title: string;
  duration?: number;
}
type Media = Book | Movie;
function describeMedia(media: Media): string {
  return `${media.title}${media.type === "book" && media.pages ? `: ${media.pages} pages` : media.type === "movie" && media.duration ? `: ${media.duration} minutes` : ""}`;
}
const book: Book = { type: "book", title: "TypeScript Guide", pages: 200 };
const movie: Movie = { type: "movie", title: "Inception", duration: 148 };
console.log(describeMedia(book)); // Çıxış: TypeScript Guide: 200 pages
console.log(describeMedia(movie)); // Çıxış: Inception: 148 minutes
// book.title = "New Book"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// Sadə mağaza sistemi
interface Product {
  readonly id: string;
  name: string;
  price?: number;
  readonly createdAt: string;
}
class ProductItem implements Product {
  readonly id: string;
  name: string;
  price?: number;
  readonly createdAt: string;
  constructor(id: string, name: string, createdAt: string, price?: number) {
    this.id = id;
    this.name = name;
    this.createdAt = createdAt;
    this.price = price;
  }
  getDetails(): string {
    return `${this.name} (ID: ${this.id})${this.price ? `: $${this.price}` : ""}, Created: ${this.createdAt}`;
  }
}
const laptop = new ProductItem("P001", "Laptop", "2025-07-08", 1200);
console.log(laptop.getDetails()); // Çıxış: Laptop (ID: P001): $1200, Created: 2025-07-08
laptop.name = "New Laptop"; // OK
// laptop.id = "P002"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// Miras alma ilə
interface StockProduct extends Product {
  readonly stockId: string;
}
const stockProduct: StockProduct = {
  id: "P001",
  name: "Mouse",
  createdAt: "2025-07-08",
  stockId: "S001"
};
console.log(`${stockProduct.name} (Stock ID: ${stockProduct.stockId})`); // Çıxış: Mouse (Stock ID: S001)
// stockProduct.stockId = "S002"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

